document.write("<article class=\"blog-post\" id=\"post_9\">");
document.write("    <h2>AV1详解(四)</h2>");
document.write("    <p class=\"post-date\">2026年02月05日</p>");
document.write("<div id=\"post_content_9\" style=\"display:none\" >");
document.write('<p><strong>Tile list OBU</strong><br />\ntile_list_obu( ) {<br />\n  output_frame_width_in_tiles_minus_1  : f(8)<br />\n  output_frame_height_in_tiles_minus_1 : f(8)<br />\n  tile_count_minus_1tile_count_minus_1 : f(16)<br />\n  for ( tile = 0; tile &lt;= tile_count_minus_1; tile++ )<br />\n    tile_list_entry( )<br />\n}</p>\n<p>tile_list_entry( ) {<br />\n  anchor_frame_idx : f(8)<br />\n  anchor_tile_row : f(8)<br />\n  anchor_tile_col : f(8)<br />\n  tile_data_size_minus_1 : f(16)<br />\n  N = 8 * (tile_data_size_minus_1 + 1)<br />\n  coded_tile_data : f(N)<br />\n}</p>');
